function Panamita({ mood = "idle", size = 64 }) {
  const anim = mood === "thinking" ? "bob 0.9s ease-in-out infinite" : "float 3s ease-in-out infinite";
  const filter = mood === "happy" ? "drop-shadow(0 0 8px rgba(255,184,0,0.7))" : "none";
  return <img src={PANAMITA_SRC} width={size} height={size} style={{ objectFit:"contain", animation:anim, filter, display:"block" }} alt="Panamita"/>;
}

const fmt = v => v >= 1e6 ? `B/. ${(v/1e6).toFixed(2)}M` : v >= 1e3 ? `B/. ${(v/1e3).toFixed(0)}K` : `B/. ${v.toFixed(0)}`;
const pct = (a,b) => b > 0 ? (a/b*100).toFixed(1) : "0.0";
const col = p => +p >= 76 ? C.green : +p >= 60 ? C.orange : C.red;

// ── LOGIN ─────────────────────────────────────────────────────────────────────
function Login({ onLogin }) {
  const [user, setUser] = useState(""); const [pass, setPass] = useState("");
  const [err, setErr] = useState(""); const [loading, setLoading] = useState(false);
  const [mood, setMood] = useState("idle");
  const doLogin = async () => {
    if (!user || !pass) { setErr("Por favor completa todos los campos."); return; }
    setLoading(true); setMood("thinking"); setErr("");
    await new Promise(r => setTimeout(r, 900));
    if (user === "admin" && pass === "diprena2025") { setMood("happy"); await new Promise(r => setTimeout(r, 400)); onLogin({ name:"Mariam", role:"Administrador", isAdmin:true }); }
    else { setMood("idle"); setErr("Usuario o contraseña incorrectos."); setLoading(false); }
  };
  return (
    <div style={{ minHeight:"100vh", background:C.bg, display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"'Segoe UI',system-ui,sans-serif" }}>
      <div style={{ width:440, background:C.white, borderRadius:16, boxShadow:"0 8px 40px rgba(0,0,0,0.10)", overflow:"hidden" }}>
        <div style={{ background:C.headerBg, padding:"32px 40px 28px", textAlign:"center" }}>
          <div style={{ display:"flex", justifyContent:"center", marginBottom:8 }}><Panamita mood={mood} size={90}/></div>
          <div style={{ color:C.gold, fontSize:24, fontWeight:800, letterSpacing:"0.04em" }}>PANANOMICS<span style={{ fontSize:16 }}>.IA</span></div>
          <div style={{ color:"rgba(255,255,255,0.55)", fontSize:12, marginTop:4, letterSpacing:"0.08em" }}>SISTEMA DE ANÁLISIS PRESUPUESTARIO</div>
        </div>
        <div style={{ padding:"32px 40px 36px" }}>
          <p style={{ color:C.text, fontSize:18, fontWeight:700, marginBottom:6 }}>Iniciar sesión</p>
          <p style={{ color:C.textMid, fontSize:13, marginBottom:24 }}>Ministerio de Economía y Finanzas · DIPRENA</p>
          {["USUARIO","CONTRASEÑA"].map((lbl,i) => (
            <div key={lbl} style={{ marginBottom:16 }}>
              <label style={{ fontSize:12, fontWeight:600, color:C.textMid, display:"block", marginBottom:6 }}>{lbl}</label>
              <input type={i===1?"password":"text"} value={i===0?user:pass} onChange={e => i===0?setUser(e.target.value):setPass(e.target.value)} onKeyDown={e => e.key==="Enter" && doLogin()} placeholder={i===0?"nombre.apellido":"••••••••"}
                style={{ width:"100%", padding:"10px 14px", border:`1.5px solid ${C.border}`, borderRadius:8, fontSize:14, color:C.text, outline:"none", boxSizing:"border-box", background:C.bg }}
                onFocus={e=>e.target.style.borderColor=C.headerBg} onBlur={e=>e.target.style.borderColor=C.border}/>
            </div>
          ))}
          {err && <div style={{ background:"#FFEBEE", border:"1px solid #FFCDD2", borderRadius:6, padding:"8px 12px", fontSize:13, color:C.red, marginBottom:16 }}>{err}</div>}
          <button onClick={doLogin} disabled={loading} style={{ width:"100%", padding:"12px", background:loading?C.textLight:C.headerBg, color:"white", border:"none", borderRadius:8, fontSize:14, fontWeight:700, cursor:loading?"not-allowed":"pointer", marginTop:8 }}>
            {loading ? "Verificando..." : "Ingresar →"}
          </button>
        </div>
      </div>
      <style>{`@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-7px)}}@keyframes bob{0%,100%{transform:rotate(-4deg)}50%{transform:rotate(4deg)}}*{box-sizing:border-box;margin:0;padding:0}`}</style>
    </div>
  );
}

