// ── ENTIDADES ─────────────────────────────────────────────────────────────────
function Entidades({ user }) {
  const ENTIDADES = useContext(EntidadesCtx);
  const [view, setView] = useState("lista");
  const [selected, setSelected] = useState(null);
  const [openGroups, setOpenGroups] = useState({0:true,1:false,2:false,3:false});
  const GRUPO_NAMES = ["GOBIERNO CENTRAL","INSTITUCIONES DESCENTRALIZADAS","EMPRESAS PÚBLICAS","INTERMEDIARIOS FINANCIEROS"];
  const GRUPO_COLORS = [C.navDash, C.navHistorico, C.navInformes, C.navEntidades];
  const GRUPO_ICONS = ["🏛","🏢","🏭","🏦"];
  const toggleGroup = i => setOpenGroups(prev => ({...prev,[i]:!prev[i]}));
  const grouped = {0:[],1:[],2:[],3:[]};
  ENTIDADES.forEach(e => { if (grouped[e.codigo_area] !== undefined) grouped[e.codigo_area].push(e); });

  return (
    <div style={{ minHeight:"100vh", background:C.bg, fontFamily:"'Segoe UI',system-ui,sans-serif" }}>
      <div style={{ background:C.white, borderBottom:`1px solid ${C.border}`, padding:"14px 28px", display:"flex", alignItems:"center", gap:12 }}>
        <span style={{ fontSize:22 }}>🏛</span>
        <div>
          <div style={{ fontSize:17, fontWeight:700, color:C.text }}>Repositorio por Entidad</div>
          <div style={{ fontSize:12, color:C.textMid }}>Informes de monitoreo previos · Crear nuevo informe</div>
        </div>
        {user.isAdmin && (
          <button onClick={()=>setView(view==="crear"?"lista":"crear")} style={{ marginLeft:"auto", padding:"8px 18px", background:view==="crear"?C.navEntidades:C.navInformes, color:"white", border:"none", borderRadius:8, fontSize:12, fontWeight:700, cursor:"pointer" }}>
            {view==="crear" ? "← Ver Repositorio" : "+ Crear Informe"}
          </button>
        )}
      </div>
      <div style={{ padding:"24px 28px" }}>
        {view==="crear" ? (
          <div style={{ background:C.white, borderRadius:14, padding:"28px", border:`1px solid ${C.border}`, maxWidth:700, margin:"0 auto" }}>
            <div style={{ fontSize:16, fontWeight:700, color:C.text, marginBottom:6 }}>Crear Informe de Monitoreo</div>
            <div style={{ fontSize:12, color:C.textMid, marginBottom:20 }}>Plantilla predeterminada — el analista actualiza los datos y el sistema genera el informe automáticamente.</div>
            <div style={{ background:C.navInformes+"12", border:`1px dashed ${C.navInformes}50`, borderRadius:10, padding:"20px", textAlign:"center" }}>
              <div style={{ fontSize:32, marginBottom:10 }}>🔧</div>
              <div style={{ fontSize:13, fontWeight:700, color:C.navInformes, marginBottom:6 }}>Plantilla en diseño</div>
              <div style={{ fontSize:12, color:C.textMid }}>La plantilla de informe de monitoreo se definirá en la próxima sesión de trabajo.</div>
            </div>
          </div>
        ) : (
          <div>
            {[0,1,2,3].map(i => (
              <div key={i} style={{ marginBottom:12, borderRadius:12, border:`1px solid ${GRUPO_COLORS[i]}30`, overflow:"hidden" }}>
                <div onClick={()=>toggleGroup(i)} style={{ background:GRUPO_COLORS[i]+"12", padding:"12px 18px", display:"flex", alignItems:"center", gap:10, cursor:"pointer", borderBottom: openGroups[i]?`1px solid ${GRUPO_COLORS[i]}25`:"none" }}>
                  <span style={{ fontSize:16 }}>{GRUPO_ICONS[i]}</span>
                  <div style={{ flex:1 }}>
                    <span style={{ fontSize:13, fontWeight:800, color:GRUPO_COLORS[i], letterSpacing:"0.04em" }}>{i} {GRUPO_NAMES[i]}</span>
                    <span style={{ marginLeft:10, fontSize:11, color:C.textMid, fontWeight:500 }}>{grouped[i].length} entidades</span>
                  </div>
                  <span style={{ fontSize:11, color:GRUPO_COLORS[i], fontWeight:700 }}>{openGroups[i]?"▲":"▼"}</span>
                </div>
                {openGroups[i] && (
                  <div style={{ background:C.white, padding:"16px 18px" }}>
                    <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(220px,1fr))", gap:10 }}>
                      {grouped[i].map(e => {
                        const code = `${e.codigo_area}${String(e.codigo_entidad).padStart(2,'0')}`;
                        const isSelected = selected===e.nombre;
                        return (
                          <div key={e.nombre} onClick={()=>setSelected(isSelected?null:e.nombre)}
                            style={{ background:C.white, borderRadius:10, padding:"14px 16px", border:`1px solid ${isSelected?GRUPO_COLORS[i]:C.border}`, cursor:"pointer", transition:"all 0.2s", boxShadow:isSelected?`0 4px 16px ${GRUPO_COLORS[i]}25`:"none" }}
                            onMouseEnter={ev=>{ if(!isSelected) ev.currentTarget.style.boxShadow="0 4px 12px rgba(0,0,0,0.08)"; }}
                            onMouseLeave={ev=>{ if(!isSelected) ev.currentTarget.style.boxShadow="none"; }}>
                            <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:8 }}>
                              <div style={{ padding:"3px 7px", background:GRUPO_COLORS[i]+"18", borderRadius:5, fontSize:10, fontWeight:800, color:GRUPO_COLORS[i], letterSpacing:"0.05em" }}>{code}</div>
                              <div style={{ fontSize:11, fontWeight:800, color:GRUPO_COLORS[i], letterSpacing:"0.04em" }}>{e.siglas}</div>
                            </div>
                            <div style={{ fontSize:11, color:C.textMid, lineHeight:1.4 }}>{e.nombre}</div>
                            <div style={{ marginTop:8, padding:"4px 8px", background:C.bg, borderRadius:5, fontSize:10, color:C.textLight, textAlign:"center" }}>Sin informes cargados aún</div>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

// ── BIBLIOTECA ────────────────────────────────────────────────────────────────
function Biblioteca() {
  const [tab, setTab] = useState("normativa");
  const [docs, setDocs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(null);

  const DOCS_FALLBACK = [
    { id:1, titulo:"Presupuesto General del Estado 2026", titulo_corto:"Presupuesto 2026", categoria:"Normativa Legal", anio:2026, paginas:149, icono:"📜", color:"#1565C0", resumen_contexto:"Ley del Presupuesto General del Estado de Panamá para la vigencia fiscal 2026 (Ley 494). Presupuesto total aprobado: B/. 34,900,802,375.", tabla_contenidos:JSON.stringify(["Articulado de la Ley","Títulos de gasto por institución","Entidades descentralizadas","Normas de ejecución"]) },
    { id:2, titulo:"Manual de Clasificaciones Presupuestarias 2024", titulo_corto:"Manual de Clasificaciones", categoria:"Metodología", anio:2024, paginas:186, icono:"📘", color:"#00838F", resumen_contexto:"Manual técnico oficial de DIPRENA. Define todos los clasificadores presupuestarios: institucional, fuentes de financiamiento, objeto del gasto, funcional y sectorial.", tabla_contenidos:JSON.stringify(["I. Clasificación Presupuestaria","II. Clasificación Institucional","III. Fuente de Financiamiento","IV. Objeto del Gasto","V. Clasificaciones Complementarias"]) },
    { id:3, titulo:"Clasificador Sectorial de la Inversión Pública — SINIP", titulo_corto:"Clasificador SINIP", categoria:"Metodología", anio:2001, paginas:48, icono:"🗂️", color:"#4A5568", resumen_contexto:"Manual del SINIP que define la clasificación sectorial para proyectos de inversión pública: Social, Infraestructura, Productiva, Administración y Justicia, Ambiente.", tabla_contenidos:JSON.stringify(["I. Introducción","II. Conceptos básicos","III. Criterios generales","IV. Criterios específicos","Resumen clasificación sectorial"]) },
    { id:4, titulo:"Plan Estratégico de Gobierno 2025–2029", titulo_corto:"PEG 2025–2029", categoria:"Planificación", anio:2025, paginas:5, icono:"🎯", color:"#6C5CE7", resumen_contexto:"Define los 4 pilares del PEG 2025-2029: Impulso a sectores económicos, Oportunidades para todos, Gobernanza eficiente, Sostenibilidad ambiental.", tabla_contenidos:JSON.stringify(["Pilar 1 — Impulso económico","Pilar 2 — Oportunidades para todos","Pilar 3 — Gobernanza eficiente","Pilar 4 — Sostenibilidad ambiental"]) },
    { id:5, titulo:"Informe de Ejecución — Cierre Fiscal 2024", titulo_corto:"Ejecución Cierre 2024", categoria:"Ejecución Presupuestaria", anio:2024, paginas:23, icono:"📊", color:"#E53935", resumen_contexto:"Informe oficial DIPRENA. Presupuesto: B/. 30,690M. Ejecución global: 85%. Gobierno Central 91%, Descentralizadas 87%, Empresas Públicas 84%.", tabla_contenidos:JSON.stringify(["Resumen Ejecutivo","Ingresos","Distribución Institucional","Clasificación Sectorial","Conclusiones"]) },
    { id:6, titulo:"Presupuesto Ciudadano 2026", titulo_corto:"Presupuesto Ciudadano 2026", categoria:"Transparencia Fiscal", anio:2026, paginas:13, icono:"👥", color:"#FB8C00", resumen_contexto:"Documento de transparencia fiscal del MEF. Explica el PGE 2026 (B/. 34,900M) en lenguaje accesible: ciclo presupuestario, fuentes y distribución del gasto.", tabla_contenidos:JSON.stringify(["1. Introducción","2. Presupuesto 2026","3. Ingresos","4. Gastos","5. Proyectos por provincia"]) },
  ];

  useEffect(() => { loadDocs(); }, []);

  const loadDocs = async () => {
    setLoading(true);
    try {
      const data = await sbQuery("documentos", "select=*&order=anio.desc");
      setDocs(Array.isArray(data) && data.length > 0 ? data : DOCS_FALLBACK);
    } catch { setDocs(DOCS_FALLBACK); }
    setLoading(false);
  };

  const normativa = docs.filter(d => d.categoria !== "PEI");
  const peiByCategoria = PEI_DOCS.reduce((acc,d)=>{ (acc[d.categoria]??=[]).push(d); return acc; }, {});

  const Book = ({ doc, isSelected }) => {
    const [hovered, setHovered] = useState(false);
    const lift = hovered || isSelected;
    return (
      <div onClick={() => setSelected(isSelected ? null : doc)} onMouseEnter={() => setHovered(true)} onMouseLeave={() => setHovered(false)}
        style={{ cursor:"pointer", transform:lift?"translateY(-18px)":"translateY(0)", transition:"transform 0.3s cubic-bezier(0.34,1.56,0.64,1)", position:"relative", zIndex:lift?10:1 }}>
        <div style={{ width:52, height:160, background:`linear-gradient(90deg,${doc.color}dd 0%,${doc.color}dd 8px,${doc.color} 8px)`, borderRadius:"2px 4px 4px 2px", boxShadow:lift?"4px 8px 20px rgba(0,0,0,0.35)":"2px 3px 8px rgba(0,0,0,0.25)", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:"10px 6px", position:"relative", overflow:"hidden" }}>
          <div style={{ fontSize:18, marginBottom:8 }}>{doc.icono}</div>
          <div style={{ writingMode:"vertical-rl", textOrientation:"mixed", transform:"rotate(180deg)", fontSize:9, fontWeight:700, color:"white", letterSpacing:"0.06em", lineHeight:1.3, textAlign:"center", maxHeight:90, overflow:"hidden" }}>{doc.titulo_corto}</div>
          <div style={{ position:"absolute", bottom:5, fontSize:8, color:"rgba(255,255,255,0.5)" }}>{doc.anio}</div>
          {isSelected && <div style={{ position:"absolute", inset:0, background:"rgba(255,184,0,0.15)", border:"2px solid rgba(255,184,0,0.7)", borderRadius:"2px 4px 4px 2px", pointerEvents:"none" }}/>}
        </div>
        {hovered && !isSelected && (
          <div style={{ position:"absolute", bottom:"calc(100% + 8px)", left:"50%", transform:"translateX(-50%)", background:C.navy, color:"white", fontSize:10, fontWeight:600, padding:"4px 8px", borderRadius:5, whiteSpace:"nowrap", zIndex:100, pointerEvents:"none" }}>
            {doc.titulo_corto}
            <div style={{ position:"absolute", top:"100%", left:"50%", transform:"translateX(-50%)", borderLeft:"4px solid transparent", borderRight:"4px solid transparent", borderTop:`4px solid ${C.navy}` }}/>
          </div>
        )}
      </div>
    );
  };

  const Shelf = ({ items, label }) => (
    <div style={{ marginBottom:24 }}>
      <div style={{ fontSize:12, fontWeight:700, color:C.textMid, letterSpacing:"0.1em", marginBottom:12 }}>{label}</div>
      <div style={{ background:"#F5E6D3", borderRadius:14, padding:"20px 20px 0", boxShadow:"inset 0 2px 8px rgba(0,0,0,0.06), 0 4px 16px rgba(0,0,0,0.07)" }}>
        <div style={{ padding:"20px 30px 0" }}>
          <div style={{ display:"flex", alignItems:"flex-end", gap:6, minHeight:190 }}>
            <div style={{ width:14, height:140, background:"linear-gradient(90deg,#6B4423,#8B5E3C)", borderRadius:"4px 2px 2px 4px", flexShrink:0, alignSelf:"flex-end" }}/>
            {items.map(doc=><Book key={doc.id} doc={doc} isSelected={selected?.id===doc.id}/>)}
            <div style={{ width:14, height:120, background:"linear-gradient(90deg,#8B5E3C,#6B4423)", borderRadius:"2px 4px 4px 2px", flexShrink:0, alignSelf:"flex-end" }}/>
            <div style={{ width:52, height:130, border:`2px dashed ${C.border}`, borderRadius:4, display:"flex", alignItems:"center", justifyContent:"center", color:C.textLight, fontSize:20, flexShrink:0, alignSelf:"flex-end" }}>+</div>
          </div>
        </div>
        <div style={{ height:16, background:"linear-gradient(180deg,#A8784F 0%,#8B5E3C 40%,#6B4423 100%)", margin:"0 -20px", boxShadow:"0 5px 14px rgba(0,0,0,0.25)" }}/>
        <div style={{ height:10, background:"linear-gradient(180deg,#6B4423,#4A2E1A)", margin:"0 -20px", borderRadius:"0 0 14px 14px" }}/>
      </div>
    </div>
  );

  const BookDetail = ({ doc }) => {
    const [showPdf, setShowPdf] = useState(false);
    let chapters = [];
    try { chapters = JSON.parse(doc.tabla_contenidos||"[]"); } catch {}
    return (
      <div style={{ background:C.white, borderRadius:14, border:`1px solid ${C.border}`, boxShadow:"0 8px 24px rgba(0,0,0,0.10)", overflow:"hidden", animation:"slideIn 0.3s ease", marginTop:20 }}>
        <div style={{ background:`linear-gradient(135deg,${doc.color},${doc.color}aa)`, padding:"18px 22px", display:"flex", alignItems:"flex-start", gap:12 }}>
          <div style={{ fontSize:32 }}>{doc.icono}</div>
          <div style={{ flex:1 }}>
            <div style={{ fontSize:10, color:"rgba(255,255,255,0.6)", letterSpacing:"0.12em", fontWeight:600, marginBottom:3 }}>{doc.categoria?.toUpperCase()}</div>
            <div style={{ fontSize:15, fontWeight:800, color:"white", lineHeight:1.3 }}>{doc.titulo}</div>
            <div style={{ display:"flex", gap:8, marginTop:6, flexWrap:"wrap" }}>
              <span style={{ padding:"2px 8px", background:"rgba(255,255,255,0.2)", borderRadius:10, fontSize:11, color:"white" }}>📅 {doc.anio}</span>
              {doc.paginas && <span style={{ padding:"2px 8px", background:"rgba(255,255,255,0.2)", borderRadius:10, fontSize:11, color:"white" }}>📄 {doc.paginas} págs.</span>}
            </div>
          </div>
          <div style={{ display:"flex", gap:6, alignItems:"center" }}>
            {doc.pdf && (
              <>
                <button onClick={()=>setShowPdf(v=>!v)} style={{ background:"rgba(255,255,255,0.25)", border:"1px solid rgba(255,255,255,0.4)", color:"white", padding:"5px 12px", borderRadius:7, cursor:"pointer", fontSize:11, fontWeight:700 }}>
                  {showPdf ? "▲ Cerrar" : "👁 Ver PDF"}
                </button>
                <a href={doc.pdf} download style={{ background:"rgba(255,255,255,0.25)", border:"1px solid rgba(255,255,255,0.4)", color:"white", padding:"5px 12px", borderRadius:7, cursor:"pointer", fontSize:11, fontWeight:700, textDecoration:"none" }}>
                  ⬇ Descargar
                </a>
              </>
            )}
            <button onClick={()=>setSelected(null)} style={{ background:"rgba(255,255,255,0.2)", border:"none", color:"white", width:26, height:26, borderRadius:"50%", cursor:"pointer", fontSize:13, display:"flex", alignItems:"center", justifyContent:"center" }}>✕</button>
          </div>
        </div>
        <div style={{ padding:"18px 22px" }}>
          <div style={{ fontSize:12, color:C.textMid, lineHeight:1.7, marginBottom:14 }}>{doc.resumen_contexto}</div>
          {chapters.length > 0 && <>
            <div style={{ fontSize:11, fontWeight:700, color:C.text, letterSpacing:"0.08em", marginBottom:8 }}>CONTENIDO</div>
            <div style={{ display:"flex", flexDirection:"column", gap:5, marginBottom:14 }}>
              {chapters.map((ch,i)=>(
                <div key={i} style={{ display:"flex", alignItems:"center", gap:8, padding:"7px 10px", background:C.bg, borderRadius:7, fontSize:12, color:C.text, border:`1px solid ${C.border}` }}>
                  <div style={{ width:18, height:18, borderRadius:"50%", background:doc.color+"20", color:doc.color, fontSize:9, fontWeight:700, display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0 }}>{i+1}</div>
                  {ch}
                </div>
              ))}
            </div>
          </>}
          {doc.pdf && showPdf && (
            <div style={{ borderRadius:10, overflow:"hidden", border:`1px solid ${C.border}`, marginBottom:14 }}>
              <iframe src={doc.pdf} title={doc.titulo} width="100%" height="620px" style={{ display:"block", border:"none" }}/>
            </div>
          )}
          {!doc.pdf && (
            <div style={{ marginTop:14, padding:"8px 12px", background:C.gold+"15", borderRadius:8, border:`1px solid ${C.gold}40`, fontSize:11, color:"#8B6914" }}>
              ✦ Panamita usa este documento automáticamente al analizar el presupuesto
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div style={{ minHeight:"100vh", background:C.bg, fontFamily:"'Segoe UI',system-ui,sans-serif" }}>
      <div style={{ background:C.white, borderBottom:`1px solid ${C.border}`, padding:"14px 28px", display:"flex", alignItems:"center", gap:12 }}>
        <span style={{ fontSize:22 }}>📚</span>
        <div>
          <div style={{ fontSize:17, fontWeight:700, color:C.text }}>Biblioteca</div>
          <div style={{ fontSize:12, color:C.textMid }}>Documentos normativos · Planes Estratégicos Institucionales</div>
        </div>
        <div style={{ marginLeft:"auto" }}><Panamita size={34}/></div>
      </div>
      <div style={{ padding:"24px 28px" }}>
        {/* Tabs */}
        <div style={{ display:"flex", gap:4, background:C.white, borderRadius:10, padding:4, boxShadow:`0 1px 4px rgba(0,0,0,0.07)`, marginBottom:24, width:"fit-content" }}>
          {[["normativa","📜 Normativa y Metodología",C.navBiblioteca],["pei","🎯 Planes Estratégicos (PEI)",C.navHistorico]].map(([id,lbl,clr])=>(
            <button key={id} onClick={()=>{setTab(id);setSelected(null);}} style={{ padding:"7px 20px", borderRadius:7, border:"none", background:tab===id?clr:"transparent", color:tab===id?"white":C.textMid, fontSize:12, fontWeight:tab===id?700:500, cursor:"pointer", transition:"all 0.2s" }}>{lbl}</button>
          ))}
        </div>

        {loading ? (
          <div style={{ display:"flex", alignItems:"center", justifyContent:"center", height:200, gap:12 }}>
            <Panamita mood="thinking" size={50}/><span style={{ color:C.textMid }}>Cargando biblioteca...</span>
          </div>
        ) : tab==="normativa" ? (
          <>
            <Shelf items={normativa} label="DOCUMENTOS NORMATIVOS Y METODOLÓGICOS"/>
            {selected && selected.categoria !== "PEI" && <BookDetail doc={selected}/>}
          </>
        ) : (
          <>
            {Object.entries(peiByCategoria).map(([cat, items]) => (
              <Shelf key={cat} items={items} label={cat.toUpperCase()}/>
            ))}
            {selected && <BookDetail doc={selected}/>}
          </>
        )}
      </div>
      <style>{`@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-7px)}}@keyframes bob{0%,100%{transform:rotate(-4deg)}50%{transform:rotate(4deg)}}@keyframes slideIn{from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)}}::-webkit-scrollbar{width:5px}::-webkit-scrollbar-thumb{background:${C.border};border-radius:3px}`}</style>
    </div>
  );
}

// ── CHAT ──────────────────────────────────────────────────────────────────────
function ChatView({ user }) {
  const ENTIDADES = useContext(EntidadesCtx);
  const [messages, setMessages] = useState([{ role:"assistant", text:`¡Hola ${user.name}! Soy **Panamita** 👋 Estoy conectada a la base de datos en tiempo real.\n\nTengo acceso a **${ENTIDADES.length} entidades** (2016–2026), **34 documentos** (normativa + PEI/POA de 28 instituciones). Puedes preguntarme:\n\n• _¿Cómo ejecutó MEDUCA en 2024?_\n• _¿Qué entidades reciben fondos FECCI en el sector agropecuario?_\n• _Compara MINSA vs MIDA en inversión 2023_\n• _Entidades financiadas con Dividendos del Canal_\n\n¿Qué quieres analizar?` }]);
  const [input, setInput] = useState(""); const [loading, setLoading] = useState(false);
  const [mood, setMood] = useState("idle"); const [dbCtx, setDbCtx] = useState(""); const [libCtx, setLibCtx] = useState("");
  const bottomRef = useRef(null);
  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior:"smooth" }); }, [messages]);
  useEffect(() => { loadContexts(); }, []);
  useEffect(() => {
    setMessages(prev => {
      if (prev.length === 1 && prev[0].role === "assistant") {
        return [{ role:"assistant", text:`¡Hola ${user.name}! Soy **Panamita** 👋 Estoy conectada a la base de datos en tiempo real.

Tengo acceso a **${ENTIDADES.length} entidades** (2016–2026), **34 documentos** (normativa + PEI/POA de 28 instituciones). Puedes preguntarme:

• _¿Cómo ejecutó MEDUCA en 2024?_
• _¿Qué entidades reciben fondos FECCI en el sector agropecuario?_
• _Compara MINSA vs MIDA en inversión 2023_
• _Entidades financiadas con Dividendos del Canal_

¿Qué quieres analizar?` }];
      }
      return prev;
    });
  }, [ENTIDADES.length]);

  const loadContexts = async () => {
    // Presupuesto: RPC retorna resumen completo (872 entidad/año) sin límite de filas
    try {
      const raw = await sbRpc("get_resumen_para_chat", {});
      const ctx = typeof raw === "string" ? raw : (Array.isArray(raw) ? raw[0] : null);
      if (ctx) setDbCtx(ctx);
    } catch {}
    // Documentos: tabla normativa + PEI_DOCS
    const peiCtx = PEI_DOCS.map(d=>`[${d.titulo_corto} (${d.anio})]: ${d.resumen_contexto}`).join("\n");
    try {
      const docs = await sbQuery("documentos","select=titulo_corto,resumen_contexto");
      const dbCtxDocs = docs?.length ? docs.map(d=>`[${d.titulo_corto}]: ${d.resumen_contexto?.slice(0,300)}`).join("\n") : "";
      setLibCtx([dbCtxDocs, peiCtx].filter(Boolean).join("\n\n"));
    } catch { setLibCtx(peiCtx); }
  };

  const PANAMITA_TOOLS = [{
    name: "consultar_presupuesto",
    description: "Consulta datos detallados del presupuesto de Panamá filtrados por fuente de ingreso, entidad, año, tipo o programa. Úsala para preguntas cruzadas como: entidades que reciben fondos de una fuente específica, comparaciones sectoriales, análisis por fuente de financiamiento, o detalles no disponibles en el resumen general.",
    input_schema: {
      type: "object",
      properties: {
        fuente_ingreso: { type:"string", description:"Fuente de financiamiento (ej: 'FECCI', 'BID', 'Ingresos Corrientes', 'Dividendos del Canal')" },
        nombre_entidad: { type:"string", description:"Nombre parcial o completo de la entidad (ej: 'MIDA', 'Ministerio de Salud')" },
        anio:           { type:"integer", description:"Año fiscal entre 2016 y 2025" },
        tipo_presupuesto:{ type:"string", description:"FUNCIONAMIENTO o INVERSION" },
        nombre_programa:{ type:"string", description:"Nombre parcial del programa presupuestario" }
      }
    }
  }];

  const SYSTEM_PROMPT = `Eres Panamita, asistente de análisis presupuestario de PANANOMICS.IA (DIPRENA — MEF de Panamá).

RESUMEN PRESUPUESTARIO (872 combinaciones entidad/año, 2016–2025):
${dbCtx}

BIBLIOTECA DOCUMENTAL (normativa + PEI/POA/planes de 28 instituciones):
${libCtx}

REGLAS: Meta ≥76%=✓ | 60-75%=⚠ | <60%=✗. Responde en español con markdown. Sé preciso con cifras.
Cuando necesites datos cruzados (por fuente de ingreso, sector, programa, etc.) usa la herramienta consultar_presupuesto.`;

  const send = async () => {
    if (!input.trim() || loading) return;
    const txt = input.trim(); setInput("");
    setMessages(p=>[...p,{ role:"user", text:txt }]);
    setLoading(true); setMood("thinking");

    // Construir historial API (solo mensajes texto del estado)
    const apiMsgs = messages.slice(1).concat([{role:"user",text:txt}]).map(m=>({role:m.role,content:m.text}));

    try {
      let d = await fetch("https://api.anthropic.com/v1/messages",{
        method:"POST", headers:{"Content-Type":"application/json"},
        body:JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000,
          system:SYSTEM_PROMPT, tools:PANAMITA_TOOLS, messages:apiMsgs })
      }).then(r=>r.json());

      // Loop de tool use: Panamita puede llamar a la BD las veces que necesite
      while (d.stop_reason === "tool_use") {
        const toolBlock = d.content.find(b=>b.type==="tool_use");
        const inp = toolBlock.input;
        // Indicador visual mientras consulta BD
        setMessages(p=>[...p,{role:"assistant",text:`🔍 _Consultando base de datos..._`}]);
        // Llamar RPC
        const rows = await sbRpc("consultar_presupuesto_chat",{
          p_fuente:   inp.fuente_ingreso || null,
          p_entidad:  inp.nombre_entidad || null,
          p_anio:     inp.anio           || null,
          p_tipo:     inp.tipo_presupuesto || null,
          p_programa: inp.nombre_programa  || null,
        });
        const toolResult = rows.length
          ? rows.map(r=>`${r.nombre_entidad} | ${r.fuente_ingreso||'-'} | ${r.anio} | ${r.tipo_presupuesto}: B/.${(+r.total_mod/1e6).toFixed(2)}M mod | B/.${(+r.total_eje/1e6).toFixed(2)}M eje | ${r.pct_ejecucion}%`).join("\n")
          : "Sin resultados para los filtros indicados.";
        // Eliminar el indicador temporal
        setMessages(p=>p.filter(m=>m.text!==`🔍 _Consultando base de datos..._`));
        // Continuar con tool_result
        apiMsgs.push({ role:"assistant", content: d.content });
        apiMsgs.push({ role:"user", content:[{ type:"tool_result", tool_use_id:toolBlock.id, content:toolResult }] });
        d = await fetch("https://api.anthropic.com/v1/messages",{
          method:"POST", headers:{"Content-Type":"application/json"},
          body:JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000,
            system:SYSTEM_PROMPT, tools:PANAMITA_TOOLS, messages:apiMsgs })
        }).then(r=>r.json());
      }

      const text = d.content?.find(b=>b.type==="text")?.text || d.content?.[0]?.text || "Error al procesar.";
      setMessages(p=>[...p,{role:"assistant",text}]);
      setMood("happy"); setTimeout(()=>setMood("idle"),2000);
    } catch(e) { setMessages(p=>[...p,{role:"assistant",text:"Error de conexión."}]); setMood("idle"); }
    setLoading(false);
  };

  const fmtTxt = t => t.replace(/\*\*(.*?)\*\*/g,"<strong>$1</strong>").replace(/_(.*?)_/g,"<em>$1</em>").replace(/\n/g,"<br/>");
  const chips = ["Comparar todas las entidades 2024","¿Quién ejecutó mejor en 2023?","Análisis MINSA 2020–2025","Entidades con ejecución crítica"];

  return (
    <div style={{ display:"flex", flexDirection:"column", height:"100vh", background:C.bg }}>
      <div style={{ background:C.white, borderBottom:`1px solid ${C.border}`, padding:"12px 24px", display:"flex", alignItems:"center", gap:12 }}>
        <Panamita mood={mood} size={44}/>
        <div>
          <div style={{ fontSize:16, fontWeight:700, color:C.text }}>Panamita</div>
          <div style={{ fontSize:12, color:loading?C.orange:C.green, fontWeight:600 }}>{loading?"● Analizando...":`● Conectada · ${ENTIDADES.length} entidades · 34 documentos`}</div>
        </div>
        <div style={{ marginLeft:"auto", display:"flex", gap:8 }}>
          <span style={{ padding:"4px 12px", background:C.headerBg+"15", color:C.headerBg, borderRadius:20, fontSize:11, fontWeight:700 }}>202,526 registros</span>
          <span style={{ padding:"4px 12px", background:C.gold+"22", color:"#8B6914", borderRadius:20, fontSize:11, fontWeight:700 }}>2016–2026</span>
        </div>
      </div>
      <div style={{ flex:1, overflowY:"auto", padding:"20px 24px", display:"flex", flexDirection:"column", gap:14 }}>
        {messages.map((m,i)=>(
          <div key={i} style={{ display:"flex", justifyContent:m.role==="user"?"flex-end":"flex-start", alignItems:"flex-start", gap:10 }}>
            {m.role==="assistant" && <div style={{ flexShrink:0, marginTop:2 }}><Panamita mood="idle" size={34}/></div>}
            <div style={{ maxWidth:"72%", padding:"12px 16px", borderRadius:m.role==="user"?"16px 16px 4px 16px":"16px 16px 16px 4px", background:m.role==="user"?C.headerBg:C.white, color:m.role==="user"?"white":C.text, fontSize:13, lineHeight:1.7, boxShadow:"0 2px 8px rgba(0,0,0,0.07)", border:m.role==="assistant"?`1px solid ${C.border}`:"none" }} dangerouslySetInnerHTML={{__html:fmtTxt(m.text)}}/>
            {m.role==="user" && <div style={{ width:30, height:30, borderRadius:"50%", background:`linear-gradient(135deg,${C.headerBg},${C.gold})`, display:"flex", alignItems:"center", justifyContent:"center", fontSize:12, fontWeight:700, color:"white", flexShrink:0, marginTop:2 }}>M</div>}
          </div>
        ))}
        {loading && (
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <Panamita mood="thinking" size={34}/>
            <div style={{ padding:"12px 16px", background:C.white, borderRadius:"16px 16px 16px 4px", border:`1px solid ${C.border}` }}>
              <div style={{ display:"flex", gap:5 }}>{[0,1,2].map(i=><div key={i} style={{ width:7, height:7, borderRadius:"50%", background:C.headerBg, animation:`dotbounce 1.2s ease-in-out ${i*0.2}s infinite` }}/>)}</div>
            </div>
          </div>
        )}
        <div ref={bottomRef}/>
      </div>
      <div style={{ padding:"0 24px 8px", display:"flex", gap:6, flexWrap:"wrap" }}>
        {chips.map(c=><button key={c} onClick={()=>setInput(c)} style={{ padding:"5px 12px", background:C.white, border:`1px solid ${C.border}`, borderRadius:20, color:C.textMid, fontSize:11, cursor:"pointer" }} onMouseEnter={e=>{e.currentTarget.style.borderColor=C.headerBg;e.currentTarget.style.color=C.headerBg;}} onMouseLeave={e=>{e.currentTarget.style.borderColor=C.border;e.currentTarget.style.color=C.textMid;}}>{c}</button>)}
      </div>
      <div style={{ background:C.white, borderTop:`1px solid ${C.border}`, padding:"10px 24px 14px", display:"flex", gap:10, alignItems:"flex-end" }}>
        <textarea value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&!e.shiftKey){e.preventDefault();send();}}} placeholder="Escríbele a Panamita... (Enter para enviar)" rows={1}
          style={{ flex:1, padding:"10px 14px", border:`1.5px solid ${C.border}`, borderRadius:10, fontSize:13, color:C.text, background:C.bg, resize:"none", outline:"none", lineHeight:1.6 }}
          onFocus={e=>e.target.style.borderColor=C.headerBg} onBlur={e=>e.target.style.borderColor=C.border}/>
        <button onClick={send} disabled={loading||!input.trim()} style={{ width:42, height:42, borderRadius:10, background:(!loading&&input.trim())?C.headerBg:C.textLight, border:"none", color:"white", fontSize:16, cursor:(!loading&&input.trim())?"pointer":"not-allowed", flexShrink:0 }}>▶</button>
      </div>
      <style>{`@keyframes dotbounce{0%,80%,100%{transform:scale(0.6);opacity:0.4}40%{transform:scale(1);opacity:1}}@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-7px)}}@keyframes bob{0%,100%{transform:rotate(-4deg)}50%{transform:rotate(4deg)}}textarea::placeholder{color:#C5C7D0}::-webkit-scrollbar{width:5px}::-webkit-scrollbar-thumb{background:${C.border};border-radius:3px}`}</style>
    </div>
  );
}

// ── APP ───────────────────────────────────────────────────────────────────────
export default function App() {
  const [user, setUser] = useState(null);
  const [active, setActive] = useState("chat");
  const [entidades, setEntidades] = useState(ENTIDADES_FALLBACK);

  useEffect(() => {
    sbQuery("entidades", "select=nombre,siglas,codigo_area,codigo_entidad&order=codigo_area,codigo_entidad")
      .then(rows => {
        if (rows?.length) {
          setEntidades(rows.filter(r => r.nombre));
          const sigMap = {};
          rows.forEach(r => { if (r.nombre && r.siglas) sigMap[r.nombre] = r.siglas; });
          Object.assign(SIGLAS, sigMap);
        }
      }).catch(() => {});
  }, []);

  if (!user) return <Login onLogin={setUser}/>;
  const views = {
    chat: <ChatView user={user}/>,
    dashboard: <Dashboard/>,
    historico: <Dashboard/>,
    informes: <Informes/>,
    entidades: <Entidades user={user}/>,
    biblioteca: <Biblioteca/>,
  };
  return (
    <EntidadesCtx.Provider value={entidades}>
      <div style={{ display:"flex", minHeight:"100vh", fontFamily:"'Segoe UI',system-ui,sans-serif" }}>
        <Sidebar active={active} setActive={setActive} user={user} onLogout={()=>{setUser(null);setActive("chat");}}/>
        <div style={{ flex:1 }}>{views[active]||views.chat}</div>
      </div>
    </EntidadesCtx.Provider>
  );
}
